%to match the data
figure; hold on;
shadedErrorBar(linspace(-0.75,1.25,size(data_opto_fac_avg,2)),data_opto_fac_avg,data_opto_fac_sem,'r');
% shadedErrorBar(linspace(-0.75,1.25,size(data_opto_fac_delayed_avg,2)),data_opto_fac_delayed_avg,data_opto_fac_delayed_sem,'r--');
